import{_ as t,a}from"./chunks/频繁报错提示.B4wBXruJ.js";import{_ as i,o as s,c as r,a2 as l}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Limites de fréquence utilisateur","description":"","frontmatter":{},"headers":[],"relativePath":"fr-FR/Safety/user-rate-limits.md","filePath":"fr-FR/Safety/user-rate-limits.md","lastUpdated":1781962217000}'),n={name:"fr-FR/Safety/user-rate-limits.md"};function o(u,e,d,p,c,m){return s(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="limites-de-frequence-utilisateur" tabindex="-1">Limites de fréquence utilisateur <a class="header-anchor" href="#limites-de-frequence-utilisateur" aria-label="Permalink to &quot;Limites de fréquence utilisateur&quot;">​</a></h1><p>Les limites de fréquence contrôlent l’usage lorsqu’une IP ou un utilisateur effectue trop d’actions en peu de temps.</p><p>Sur un site avec upload public, cette fonction aide à réduire le spam, les abus et les envois massifs non souhaités.</p><h2 id="ou-configurer" tabindex="-1">Où configurer <a class="header-anchor" href="#ou-configurer" aria-label="Permalink to &quot;Où configurer&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Paramètres système -&gt; Sécurité -&gt; Limites de fréquence</span></span></code></pre></div><p><img src="'+t+`" alt="Limites de fréquence" loading="lazy"></p><h2 id="options-principales" tabindex="-1">Options principales <a class="header-anchor" href="#options-principales" aria-label="Permalink to &quot;Options principales&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td>Activer</td><td>Active ou désactive la limite</td></tr><tr><td>Fenêtre de temps</td><td>Période utilisée pour compter les actions</td></tr><tr><td>Nombre maximal</td><td>Nombre d’actions autorisées dans la fenêtre</td></tr><tr><td>Action ciblée</td><td>Upload ou autre opération à limiter</td></tr><tr><td>Durée de blocage</td><td>Durée du blocage après dépassement</td></tr></tbody></table><h2 id="exemple-raisonnable" tabindex="-1">Exemple raisonnable <a class="header-anchor" href="#exemple-raisonnable" aria-label="Permalink to &quot;Exemple raisonnable&quot;">​</a></h2><p>Pour un upload public, commencez avec une configuration modérée et ajustez selon l’usage réel.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>30 actions toutes les 10 minutes</span></span>
<span class="line"><span>blocage de 30 minutes en cas de dépassement</span></span></code></pre></div><p>Ce type de réglage laisse travailler les utilisateurs normaux tout en freinant les comportements manifestement anormaux.</p><h2 id="message-de-limite" tabindex="-1">Message de limite <a class="header-anchor" href="#message-de-limite" aria-label="Permalink to &quot;Message de limite&quot;">​</a></h2><p>Lorsqu’une limite est dépassée, l’utilisateur voit un message indiquant que l’action a été refusée.</p><p><img src="`+a+'" alt="Message d’erreurs fréquentes" loading="lazy"></p><h2 id="conseils" tabindex="-1">Conseils <a class="header-anchor" href="#conseils" aria-label="Permalink to &quot;Conseils&quot;">​</a></h2><ul><li>Une limite trop stricte peut bloquer des uploads légitimes par lot.</li><li>Sur un site public, évitez de laisser l’upload totalement illimité.</li><li>Combinez avec la géolocalisation IP et la gestion des utilisateurs pour enquêter sur les abus.</li><li>En cas de pic temporaire attendu, vous pouvez assouplir la limite pendant une période.</li></ul>',17)])])}const g=i(n,[["render",o]]);export{f as __pageData,g as default};
